// Extract the AI-generated response and prepare for database update
const webhookData = $node['Webhook Trigger'].json;
const draftData = $node['Save Draft Exam'].json;
const googleResponse = $node['Google AI Request'].json;

// Extract the AI-generated text
const aiText = googleResponse.candidates[0].content.parts[0].text;

// DEBUG: Log the raw AI response
console.log("=== AI RESPONSE DEBUG ===");
console.log("Raw AI Text:", aiText);
console.log("AI Text Length:", aiText.length);
console.log("=== END DEBUG ===");

// Parse the AI response to extract JSON with multiple strategies
let aiQuestions;
try {
  // Strategy 1: Remove all markdown code blocks
  let cleanText = aiText.replace(/```json\s*\n?|```\s*\n?/g, '').trim();

  // Strategy 2: Find JSON between curly braces
  const jsonMatch = cleanText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    cleanText = jsonMatch[0];
  }

  // Strategy 3: Remove any leading/trailing text that's not JSON
  const lines = cleanText.split('\n');
  let jsonStart = -1;
  let jsonEnd = -1;

  for (let i = 0; i < lines.length; i++) {
    if (lines[i].trim().startsWith('{') && jsonStart === -1) {
      jsonStart = i;
    }
    if (lines[i].trim().endsWith('}')) {
      jsonEnd = i;
    }
  }

  if (jsonStart !== -1 && jsonEnd !== -1) {
    cleanText = lines.slice(jsonStart, jsonEnd + 1).join('\n');
  }

  // DEBUG: Log the cleaned text
  console.log("=== PARSING DEBUG ===");
  console.log("Cleaned Text:", cleanText.substring(0, 500) + (cleanText.length > 500 ? '...' : ''));
  console.log("Cleaned Text Length:", cleanText.length);

  // Try to parse
  aiQuestions = JSON.parse(cleanText);

  // Validate the parsed data
  if (!aiQuestions.questions || !Array.isArray(aiQuestions.questions) || aiQuestions.questions.length === 0) {
    throw new Error("No valid questions array found in AI response");
  }

  // DEBUG: Log successful parsing
  console.log("=== PARSING SUCCESS ===");
  console.log("Parsed Questions Count:", aiQuestions.questions.length);
  console.log("Questions Summary:", aiQuestions.questions.map(q => ({ type: q.type, criteria: q.Criteria, points: q.points })));

} catch (error) {
  // DEBUG: Log parsing error
  console.log("=== PARSING ERROR ===");
  console.log("Error Message:", error.message);
  console.log("First 500 chars of AI text:", aiText.substring(0, 500));
  console.log("Last 200 chars of AI text:", aiText.substring(Math.max(0, aiText.length - 200)));
  console.log("=== CREATING FALLBACK ===");

  // Create fallback questions based on request parameters
  const requestData = webhookData.body || webhookData;
  const mcCount = requestData.multipleChoiceCount || 2;
  const codingCount = requestData.codingQuestionCount || 3;
  const totalQuestions = mcCount + codingCount;
  const mcPoints = Math.floor(40 / mcCount); // 40% of points to MC
  const codingPoints = Math.floor(60 / codingCount); // 60% of points to coding

  const fallbackQuestions = [];

  // Create multiple choice questions
  for (let i = 0; i < mcCount; i++) {
    fallbackQuestions.push({
      type: "multiple_choice",
      Criteria: `Basic ${requestData.programmingLanguage || 'PHP'} Knowledge ${i + 1}`,
      question: `What is a key concept in ${requestData.programmingLanguage || 'PHP'} programming? (Question ${i + 1})`,
      options: ["Concept A", "Concept B", "Concept C", "Concept D"],
      correct_answer: "Concept A",
      points: mcPoints
    });
  }

  // Create coding questions
  for (let i = 0; i < codingCount; i++) {
    fallbackQuestions.push({
      type: "coding",
      Criteria: `${requestData.programmingLanguage || 'PHP'} Implementation Skills ${i + 1}`,
      question: `Write a ${requestData.programmingLanguage || 'PHP'} function to solve a basic problem (Question ${i + 1})`,
      expected_output: `function solution${i + 1}() { return 'implementation'; }`,
      sample_input: "solution${i + 1}()",
      sample_output: "'implementation'",
      points: codingPoints
    });
  }

  aiQuestions = {
    exam_id: draftData.id,
    questions: fallbackQuestions,
    error: "Failed to parse AI response: " + error.message,
    raw_ai_response: aiText.substring(0, 1000) // Limit size
  };
}

// Ensure exam_id is included
if (!aiQuestions.exam_id) {
  aiQuestions.exam_id = draftData.id;
}

// Validate and enhance questions
if (aiQuestions.questions) {
  aiQuestions.questions = aiQuestions.questions.map((q, index) => {
    // Ensure Criteria field exists
    if (!q.Criteria) {
      if (q.type === 'coding') {
        q.Criteria = "Programming Implementation Skills";
      } else if (q.question && q.question.toLowerCase().includes('syntax')) {
        q.Criteria = "Language Syntax Knowledge";
      } else if (q.question && q.question.toLowerCase().includes('function')) {
        q.Criteria = "Function and Method Understanding";
      } else {
        q.Criteria = "Core Programming Concepts";
      }
    }

    // Ensure points field exists
    if (!q.points || q.points === 0) {
      q.points = q.type === 'coding' ? 20 : 10;
    }

    return q;
  });
}

// DEBUG: Log final payload
console.log("=== FINAL PAYLOAD DEBUG ===");
console.log("Final Questions Count:", aiQuestions.questions ? aiQuestions.questions.length : 0);
console.log("Total Points:", aiQuestions.questions ? aiQuestions.questions.reduce((sum, q) => sum + (q.points || 0), 0) : 0);
console.log("Question Types:", aiQuestions.questions ? aiQuestions.questions.map(q => q.type) : []);

// Prepare the update payload
const updatePayload = {
  exam_id: draftData.id,
  questions: aiQuestions.questions || [],
  metadata: {
    ai_generation: {
      model: googleResponse.modelVersion || "gemini-1.5-flash",
      tokens_used: googleResponse.usageMetadata?.totalTokenCount || 0,
      response_id: googleResponse.responseId || "unknown",
      generation_time: new Date().toISOString(),
      raw_response: aiText.substring(0, 2000), // Limit raw response size
      criteria_enabled: true,
      parsing_success: !aiQuestions.error
    },
    status: "completed"
  }
};

return [{
  json: updatePayload
}];

