// Process Google AI Response and Calculate Final Scores
const preparedData = $node['Prepare Coding-Only AI Request'].json;
const googleResponse = $node['Google AI - Coding Only'].json;

// Handle array response structure from Google AI
const responseData = Array.isArray(googleResponse) ? googleResponse[0] : googleResponse;

// Extract AI response
const aiText = responseData.candidates?.[0]?.content?.parts?.[0]?.text || responseData.content || '';

let codingAiResults;
try {
  const cleanText = aiText.replace(/```json\n?|```\n?/g, '').trim();
  codingAiResults = JSON.parse(cleanText);
  console.log('✅ Successfully parsed AI response');
} catch (error) {
  console.log('❌ Failed to parse AI response, creating fallback');

  // Create fallback for coding evaluation
  const codingQuestions = preparedData.evaluation_data.coding_questions || [];
  const answeredQuestions = codingQuestions.filter(q => q.user_answer && q.user_answer.trim().length > 0);

  let estimatedCodingScore = 0;
  const fallbackCodingScores = answeredQuestions.map((q, index) => {
    // Basic scoring based on answer length and structure
    let questionScore = 0;
    if (q.user_answer && q.user_answer.trim().length > 10) {
      questionScore += Math.round(q.points * 0.3); // 30% for attempting
      if (q.has_code_structure?.has_functions) questionScore += Math.round(q.points * 0.3);
      if (q.has_code_structure?.appears_complete) questionScore += Math.round(q.points * 0.4);
    }
    estimatedCodingScore += questionScore;

    return {
      question_id: q.id || `coding_${index + 1}`,
      Criteria: q.criteria || q.Criteria || "Programming Skills",
      score: questionScore,
      max_score: q.points || 0,
      feedback: `การประเมินอัตโนมัติ: ได้คะแนน ${questionScore} จาก ${q.points || 0} คะแนน`,
      strengths: q.user_answer?.length > 20 ? ["มีความพยายามในการเขียนโค้ด"] : ["ส่งคำตอบ"],
      improvements: ["ต้องการการพัฒนาทักษะการเขียนโค้ด"]
    };
  });

  codingAiResults = {
    coding_scores: fallbackCodingScores,
    overall_feedback: "ระบบไม่สามารถประเมินด้วย AI ได้ ใช้การประเมินอัตโนมัติแทน",
    recommendation: estimatedCodingScore > (preparedData.coding_max_score * 0.6) ? "พิจารณาเพิ่มเติม" : "ต้องการการพัฒนา"
  };
}

// Calculate final scores
const mcScore = preparedData.mc_score || 0;
const mcMaxScore = preparedData.mc_max_score || 0;
const codingScore = (codingAiResults.coding_scores || []).reduce((sum, cs) => sum + (cs.score || 0), 0);
const codingMaxScore = preparedData.coding_max_score || 0;
const totalScore = mcScore + codingScore;
const totalMaxScore = mcMaxScore + codingMaxScore;
const finalPercentage = Math.round((totalScore / totalMaxScore) * 100);

// Determine status
const status = finalPercentage >= 60 ? "passed" : "failed";

// Create comprehensive results for database update
const finalResults = {
  total_score: finalPercentage,
  status: status,

  // Multiple choice results (already calculated)
  multiple_choice_score: {
    score: mcScore,
    max_score: mcMaxScore,
    percentage: Math.round((mcScore / mcMaxScore) * 100),
    criteria_breakdown: preparedData.mc_criteria_breakdown || {}
  },

  // Coding results from Google AI
  coding_scores: codingAiResults.coding_scores || [],

  // Overall evaluation
  overall_feedback: codingAiResults.overall_feedback || "การประเมินเสร็จสิ้น",
  recommendation: codingAiResults.recommendation || (finalPercentage >= 70 ? "แนะนำให้รับเข้าทำงาน" : finalPercentage >= 50 ? "พิจารณาเพิ่มเติม" : "ไม่แนะนำ"),

  // Detailed analysis
  detailed_analysis: {
    strengths: (codingAiResults.coding_scores || []).flatMap(cs => cs.strengths || []).concat(["ทำข้อสอบครบถ้วน"]),
    weaknesses: (codingAiResults.coding_scores || []).flatMap(cs => cs.improvements || []),
    suggestions: ["ฝึกฝนการเขียนโค้ดเพิ่มเติม", "ศึกษาแนวทางการแก้ปัญหาที่หลากหลาย"]
  },

  // Score breakdown with individual question scores
  score_breakdown: {
    multiple_choice: mcScore,
    coding: codingScore,
    total: totalScore,
    total_max: totalMaxScore,
    percentage: finalPercentage,
    coding_question_scores: (codingAiResults.coding_scores || []).map(cs => ({
      question_id: cs.question_id,
      criteria: cs.Criteria,
      score: cs.score,
      max_score: cs.max_score,
      percentage: Math.round((cs.score / cs.max_score) * 100)
    }))
  },

  // Evaluation metadata
  evaluation_metadata: {
    ai_model: responseData.modelVersion || "gemini-1.5-pro",
    evaluation_timestamp: new Date().toISOString(),
    processing_method: "cost_optimized_coding_only",
    tokens_used: responseData.usageMetadata?.totalTokenCount || 0,
    response_id: responseData.responseId || "unknown",
    raw_ai_response: aiText.substring(0, 500) // First 500 chars for debugging
  }
};

return [{
  json: {
    session_id: preparedData.session_id,
    ai_results: finalResults,
    evaluation_method: "cost_optimized_ai",
    timestamp: new Date().toISOString()
  }
}];

