console.log('🤖 AI Results Data:', JSON.stringify(aiResultsData, null, 2));

// Extract the actual AI results from the nested structure
const aiResults = aiResultsData.ai_results || aiResultsData;

// Combine the data
const combinedResults = {
  // Start with AI results
  ...aiResults,

  // Override with actual MC scores from backend
  multiple_choice_score: mcScoresData.multiple_choice_score,
  candidate_info: mcScoresData.candidate_info,
  exam_template: mcScoresData.exam_template,
  session_metadata: mcScoresData.session_metadata,
  session_id: mcScoresData.session_id,

  // Recalculate total scores with correct MC scores
  score_breakdown: {
    multiple_choice: mcScoresData.multiple_choice_score.score,
    coding: aiResults.coding_scores ? aiResults.coding_scores.reduce((sum, cs) => sum + cs.score, 0) : 0,
    total: mcScoresData.multiple_choice_score.score + (aiResults.coding_scores ? aiResults.coding_scores.reduce((sum, cs) => sum + cs.score, 0) : 0),
    total_max: mcScoresData.multiple_choice_score.max_score + (aiResults.coding_scores ? aiResults.coding_scores.reduce((sum, cs) => sum + cs.max_score, 0) : 0)
  }
};

// Recalculate total percentage
if (combinedResults.score_breakdown.total_max > 0) {
  combinedResults.total_score = Math.round((combinedResults.score_breakdown.total / combinedResults.score_breakdown.total_max) * 100);
} else {
  combinedResults.total_score = 0;
}

console.log('✅ Combined Results:', JSON.stringify(combinedResults, null, 2));

return [{
  json: {
    ai_results: combinedResults,
    session_id: mcScoresData.session_id
  }
}];

